it("creates, lists, gets, updates, and deletes folders", async () => {
  const token = await registerAndLogin();

  const createResponse = await request("/folders", {
    method: "POST",
    headers: authHeaders(token),
    body: JSON.stringify({ name: "Reading" }),
  });

  expect(createResponse.status).toBe(201);
  const created = (await createResponse.json()) as FolderResponse;
  expect(created).toMatchObject({
    id: 1,
    user_id: 1,
    name: "Reading",
  });
  expect(created.created_at).toEqual(expect.any(String));
  expect(created.updated_at).toEqual(expect.any(String));

  const listResponse = await request("/folders", {
    headers: authHeaders(token),
  });
  expect(listResponse.status).toBe(200);
  await expect(listResponse.json()).resolves.toEqual([created]);

  const bookmarkResponse = await request("/bookmarks", {
    method: "POST",
    headers: authHeaders(token),
    body: JSON.stringify({
      url: "https://example.com",
      title: "Foldered bookmark",
      folder_id: created.id,
    }),
  });
  expect(bookmarkResponse.status).toBe(201);
  const bookmark = (await bookmarkResponse.json()) as BookmarkResponse;
  expect(bookmark.folder_id).toBe(created.id);

  const getResponse = await request("/folders/1", {
    headers: authHeaders(token),
  });
  expect(getResponse.status).toBe(200);
  await expect(getResponse.json()).resolves.toEqual({
    ...created,
    bookmarks: [bookmark],
  });

  const updateResponse = await request("/folders/1", {
    method: "PUT",
    headers: authHeaders(token),
    body: JSON.stringify({ name: "Reference" }),
  });
  expect(updateResponse.status).toBe(200);
  const updated = (await updateResponse.json()) as FolderResponse;
  expect(updated).toMatchObject({
    id: 1,
    name: "Reference",
    created_at: created.created_at,
  });

  const deleteResponse = await request("/folders/1", {
    method: "DELETE",
    headers: authHeaders(token),
  });
  expect(deleteResponse.status).toBe(204);

  const unfolderedResponse = await request(`/bookmarks/${bookmark.id}`, {
    headers: authHeaders(token),
  });
  expect(unfolderedResponse.status).toBe(200);
  const unfoldered = (await unfolderedResponse.json()) as BookmarkResponse;
  expect(unfoldered.folder_id).toBeNull();

  const missingResponse = await request("/folders/1", {
    headers: authHeaders(token),
  });
  expect(missingResponse.status).toBe(404);
});

