import { Router } from "express";
import type { Database as SqliteDatabase } from "better-sqlite3";
import type { Request, Response } from "express";

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type BookmarkInput = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
  folder_id?: unknown;
};

function sendValidationError(res: Response, message: string): void {
  res.status(400).json({ error: message });
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function parseBookmarkId(req: Request): number | null {
  const id = Number(req.params.id);
  return Number.isInteger(id) && id > 0 ? id : null;
}

function getAuthenticatedUserId(req: Request, res: Response): number | null {
  if (typeof req.userId !== "number") {
    res.status(401).json({ error: "missing or invalid token" });
    return null;
  }

  return req.userId;
}

function normalizeDescription(value: unknown): string | null {
  if (value === undefined || value === null) {
    return null;
  }

  if (typeof value !== "string") {
    return String(value);
  }

  return value;
}

function parseOptionalFolderId(value: unknown): number | null | undefined | false {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : false;
}

function folderExists(
  db: SqliteDatabase,
  userId: number,
  folderId: number,
): boolean {
  const folder = db
    .prepare("SELECT id FROM folders WHERE id = ? AND user_id = ?")
    .get(folderId, userId) as { id: number } | undefined;

  return folder !== undefined;
}

function validateFolderId(
  db: SqliteDatabase,
  userId: number,
  res: Response,
  value: unknown,
): number | null | undefined | false {
  const folderId = parseOptionalFolderId(value);

  if (folderId === false) {
    sendValidationError(res, "folder_id must be a positive integer");
    return false;
  }

  if (folderId === undefined || folderId === null) {
    return folderId;
  }

  if (!folderExists(db, userId, folderId)) {
    sendValidationError(res, "folder_id must reference an existing folder");
    return false;
  }

  return folderId;
}

export function createBookmarksRouter(db: SqliteDatabase): Router {
  const router = Router();

  router.post("/", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const body = req.body as BookmarkInput;

    if (!isNonEmptyString(body.url)) {
      sendValidationError(res, "url is required");
      return;
    }

    if (!isNonEmptyString(body.title)) {
      sendValidationError(res, "title is required");
      return;
    }

    const folderId = validateFolderId(db, userId, res, body.folder_id);

    if (folderId === false) {
      return;
    }

    const now = new Date().toISOString();
    const result = db
      .prepare(
        `
        INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?)
      `,
      )
      .run(
        userId,
        body.url.trim(),
        body.title.trim(),
        normalizeDescription(body.description),
        folderId ?? null,
        now,
        now,
      );

    const bookmark = db
      .prepare("SELECT * FROM bookmarks WHERE id = ?")
      .get(result.lastInsertRowid) as Bookmark;

    res.status(201).json(bookmark);
  });

  router.get("/", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const bookmarks = db
      .prepare("SELECT * FROM bookmarks WHERE user_id = ? ORDER BY id ASC")
      .all(userId) as Bookmark[];

    res.status(200).json(bookmarks);
  });

  router.get("/:id", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const id = parseBookmarkId(req);

    if (id === null) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const bookmark = db
      .prepare("SELECT * FROM bookmarks WHERE id = ? AND user_id = ?")
      .get(id, userId) as Bookmark | undefined;

    if (!bookmark) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    res.status(200).json(bookmark);
  });

  router.put("/:id", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const id = parseBookmarkId(req);

    if (id === null) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const existing = db
      .prepare("SELECT * FROM bookmarks WHERE id = ? AND user_id = ?")
      .get(id, userId) as Bookmark | undefined;

    if (!existing) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const body = req.body as BookmarkInput;

    if (body.url !== undefined && !isNonEmptyString(body.url)) {
      sendValidationError(res, "url must be a non-empty string");
      return;
    }

    if (body.title !== undefined && !isNonEmptyString(body.title)) {
      sendValidationError(res, "title must be a non-empty string");
      return;
    }

    const updatedAt = new Date().toISOString();
    const nextUrl = body.url === undefined ? existing.url : body.url.trim();
    const nextTitle =
      body.title === undefined ? existing.title : body.title.trim();
    const nextDescription =
      body.description === undefined
        ? existing.description
        : normalizeDescription(body.description);
    const folderId = validateFolderId(db, userId, res, body.folder_id);

    if (folderId === false) {
      return;
    }

    const nextFolderId =
      body.folder_id === undefined ? existing.folder_id : folderId;

    db.prepare(
      `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE id = ? AND user_id = ?
    `,
    ).run(
      nextUrl,
      nextTitle,
      nextDescription,
      nextFolderId,
      updatedAt,
      id,
      userId,
    );

    const bookmark = db
      .prepare("SELECT * FROM bookmarks WHERE id = ? AND user_id = ?")
      .get(id, userId) as Bookmark;

    res.status(200).json(bookmark);
  });

  router.delete("/:id", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const id = parseBookmarkId(req);

    if (id === null) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const result = db
      .prepare("DELETE FROM bookmarks WHERE id = ? AND user_id = ?")
      .run(id, userId);

    if (result.changes === 0) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    res.status(204).send();
  });

  return router;
}

